<template>
    <div>
        <!--Custom Loader component start-->
        <loader :is-visible="isLoading"></loader>
        <!--Custom Loader component start-->
        <tg-list :IsShowAction="true" ModuleName="CRM" SubModuleCode="CRM_LEADS" IdentityColumn="lead_id"
            :HeaderText="$t('Leads')" :ListData="LeadData" ref="tgList" :HeaderData="Headers"
            :HeaderButtons="listheaderbuttons" :TotalRecords="TotalRecords" :IsSearchFieldsOnTop="false"
            :SearchFields="leftSearchFields" :RenderRowActionMethod="renderActions"
            :ListDataCallBackFunction="FetchData" :LegendArray="LegendArray"
            :IsFilterApplied="searchCondition ? true : false" :SortExp="SortExp" :SortBy="SortBy"
            :CurrentPageNumber="PageNumber" v-on:LeftsearchButtonClick="leftCommonSearch"
            v-on:PagerButtonClick="pagerMethod" :NorecordfoundText="$t('NoRecordfound')"
            v-on:HeaderButtonClick="commonHeaderButtonClick" v-on:ActionButtonClick="actionButtonClick"
            v-on:ApplyView="OnApplyView" :ViewList="ViewList" v-on:SortdataButtonClick="sortdata"
            v-on:RefreshManageView="FetchData" :showCheckBox="true">
            <template v-slot:slotdata="{ data }">
                <template v-if="data.column.COLUMN_NAME == 'status_id'">
                    <listing-status :isfor="'CRM_LEADS'"
                        v-if="isCRMShowStausDrop(data.row.status_id, 'CRM_LEADS') == true" ref="updatestatus"
                        v-bind:dataid="data.row.lead_id" data-controller="Crm" v-bind:statuslist="StatusListForListing"
                        v-bind:item="data" data-action="index" v-bind:dataselected="data.row.status_id"
                        v-bind:callbackfunction="FetchData" v-bind:isselectedvaluestring="true">
                    </listing-status>
                    <a class="inactive-disabled" v-if="isCRMShowStausDrop(data.row.status_id, 'CRM_LEADS') == false">
                        <span v-bind:class="getStatusClass(data.row.status_id, 'status_id')">
                            {{ data.row[data.column.COLUMN_NAME] }}
                        </span>
                    </a>
                </template>
            </template>
        </tg-list>
        <!--Model Popup Start-->
        <modalquickviewdetails v-if="showQuickLeadViewModal" @close="closeQuickViewModal()" :sourceIds="idForViewRecord"
            modulename="CRM" submodulecode="CRM_LEADS" controller="crm" actions="ViewLeadDetails">
        </modalquickviewdetails>
        <modalnote v-if="showNoteModal" @close="showNoteModal = false" :leadInfo="LeadIdForViewNote" modulename="CRM"
            submodulecode="CRM_LEADS" :userid="userid" v-bind:curindex="CurIndex">
        </modalnote>
        <modalfollowupslist :srcId="souceID" :leadInfo="selectedItem" v-if="showAddEventModal" modulename="CRM"
            submodulecode="CRM_LEADS" :userid="userid" @close="closeEventViewModal">
        </modalfollowupslist>
        <modalemail v-if="showAddEmailTemplate" @close="showAddEmailTemplate = false" :selectedids="modalItem"
            :userid="userid" :companyid="companyId" submodulecode="CRM_LEADS">
            <h5 class="modal-title" slot="header">{{ $t("SendEmail") }}</h5>
        </modalemail>
        <!-- <modalconvertlead :srcId="souceID" :leadInfo="selectedItem" v-if="showConvertLead" :tokenid="tokenid" modulename="CRM" submodulecode="CRM_LEADS" :userid="userid" v-bind:baseurl="BaseUrlForManageView" @close="showConvertLead">
    </modalconvertlead>  -->
        <modalconvertlead v-if="showConvertLead" @close="closeConvertLead" :leadId="convertLeadValue.value"
            moduleName="CRM" subModuleCode="CRM_LEADS" callFrom="LeadListing">
        </modalconvertlead>
        <viewlayout v-if="ShowManageView" v-show="ShowManageView" submodulecode="CRM_LEADS" modulename="CRM"
            @close="ShowManageView = false" v-bind:callbackfunction="FetchData" :usertype="usertype">
            <h5 slot="header">{{ $t('Search') }}</h5>
        </viewlayout>
        <addadditionalowner v-if="showAdditionalOwnerPopup" @close="showAdditionalOwnerPopup = false, onChange()"
            subModuleCode="CRM_LEADS">
        </addadditionalowner>
        <searchfilter v-if="showFilter" submodulecode="CRM_LEADS" modulename="CRM" v-on:close="showFilter = false"
            v-bind:callbackfunction="FetchData" v-on:FilterData="FilterData">
            <h5 slot="header">{{ $t('Search') }}</h5>
        </searchfilter>
        <modalleadowner v-if="showLeadOwnerModal" :OwnerIds="OwnerIds" :ModuleType="ModuleType"
            @close="onCloseLeadOwner">
            <h5 slot="header">{{ $t('LeadOwner') }}</h5>
        </modalleadowner>
        <modalUpdateBulkRecords v-if="isShowUpdateBulkLead" :headerName="$t('ManageBulkLead')" subModuleCode="CRM_LEADS"
            :Ids="modalItem" @close="isShowUpdateBulkLead = false"></modalUpdateBulkRecords>
    </div>
</template>

<script>
import modalquickviewdetails from '../../../components/Common/Modal/modalquickviewdetails.vue'
import modalnote from '../../../components/Common/Modal/modalnote.vue'
import modalfollowupslist from '../../../components/Common/Modal/modalfollowupslist.vue'
import modalemail from '../../../components/Common/Modal/sendbulkemail.vue'
import modalconvertlead from '../../../components/Common/Modal/modalconvertlead.vue'
import LeadDataService from "../../../services/DataService";
import Schema from "../../CRM/Lead/LeadListingSchema";
import searchfilter from '../../../components/Common/Modal/search-filter.vue'
import addadditionalowner from '../../../components/Common/Modal/addadditionalowner.vue'
import modalleadowner from '../../../components/Common/Modal/modalleadowner.vue'
import viewlayout from '../../../components/Common/Modal/view-layout.vue'
import modalUpdateBulkRecords from '../../../components/Common/Modal/modalUpdateBulkRecords.vue'
export default {
    components: {
        viewlayout,
        addadditionalowner,
        modalleadowner,
        modalemail,
        modalconvertlead,
        modalquickviewdetails,
        modalnote,
        modalfollowupslist,
        searchfilter,
        modalUpdateBulkRecords
    },
    data() {
        return {
            isLoading: false, // For Loader
            LeadData: [], // Main dataset
            ViewList: [],
            clientemail: '',
            NameSearch: '',
            CompanyName: '',
            hdnOwnerId: '',
            Headers: [],
            souceID: 0,
            showAddEventModal: false,
            showLeadOwnerModal: false,
            TotalRecords: 0,
            PageNumber: 1,
            PageSize: 10,
            SortBy: '',
            SortExp: '',
            PageSizeOption: null,
            CurrentPage: 1,
            TotalPages: 0,
            GroupStart: 1,
            GroupEnd: 3,
            Status: '',
            OwnerId: '',
            OwnerIds: [],
            ModuleType: '',
            SearchClient: '',
            leadDateFrom: '',
            leadDateTo: '',
            SearchCompay: '',
            Channel: '',
            showImportModal: false,
            showConvertLead: false,
            showAddEmailTemplate: false,
            convertLeadValue: { value: null, name: '' },
            modalItem: [],
            showExportModal: false,
            showModal: false,
            noRecord: false,
            showFilter: false,
            searchCondition: '',
            showQuickLeadViewModal: false,
            showNoteModal: false,
            isShowLeadNoteDialogue: false,
            idForViewRecord: null,
            NoRecordForTabNotes: false,
            LeadIdForViewNote: null,
            LeadOwnerList: null,
            LeadStatusList: null,
            selectedLeadOwner: [],
            IsAnySearch: false,
            CurIndex: 0,
            ShowManageView: false,
            conditionForInstantSearch: "",
            showAdditionalOwnerPopup: false,
            listheaderbuttons: Schema.buttons,

            userid: null,
            usertype: null,
            companyId: null,
            leftSearchFields: Schema.leftsearchSchema,
            listActions: Schema.listActions,
            appliedFilter: [],
            StatusListForListing: [],
            LegendArray: [],
            privilegeParams: null,
            ViewListId: '',
            isShowUpdateBulkLead: false
        }
    },
    created: async function () {

        this.userid = this.GetUserInfo.ID
        this.usertype = this.GetUserInfo.UserType
        this.companyId = this.GetUserInfo.CompanyId;
        this.privilegeParams = `controller=CRM&action=`;
        var ths = this;
        ths.getStatuslistForListing("CRM", "en");
        await Schema.bindleftCommonSearchdropdown(ths, "CRM", "LEAD_OWNER_SEARCH"); //ths.bindleftCommonSearchdropdown("CRM","LEAD_DEAL_STATUS");//ths.GetLeadOwnerlist();
        await Schema.bindleftCommonSearchdropdown(ths, "CRM", "LEAD_DEAL_STATUS"); //ths.bindleftCommonSearchdropdown("CRM","LEAD_OWNER_SEARCH");//ths.GetSearchStatusList();           
        ths.FetchData();
        await ths.GetDdlRecords_ViewList();
        ths.LegendArray = [
            {
                class: 'legend-pending colorboxsquare',
                text: (ths.$t('CloseLeadLegend', ['Lead']))
            }
        ]
    },
    methods: {
        GetDdlRecords_ViewList: async function () {
            var vm = this;
            vm.ViewList = [];
            var url = `moduleName=CRM&subModuleCode=CRM_LEADS&viewId=0&pageSize=100&pageNum=1&sortBy=&sortExp=`;
            await LeadDataService.GetViewList(url).then(function (response) {
                if (response.data && typeof (response.data.DATA) != 'undefined') {
                    vm.ViewList = response.data.DATA;
                }
                var chkVACTIVE = 0;
                vm.ViewListId = "0";
                if (vm.ViewList == null || vm.ViewList == "") {

                }
                else {
                    vm.ViewList.forEach(function (item) {

                        if (item.IS_SLECTED_USER_ID > 0) {
                            chkVACTIVE = chkVACTIVE + 1;
                            vm.ViewListId = item.VIEW_ID;
                        }
                    });
                }
                var indx = 0;
                if (chkVACTIVE > 0) {
                    vm.ViewList.splice(indx, 0, { "SUB_MODULE_NAME": "", "SUB_MODULE_CODE": "", "VIEW_NAME": "Default View", "VIEW_ID": 0, "IS_APPLICABLE_TO_ALL": 1, "MODULE_NAME": "", "CREATED_AT": "", "IS_SLECTED_USER_ID": 0, "CAN_EDIT": 0, "ROWNUMBER": 0, "VIEW_TYPE": "", "USER_LIST": "" });
                }
                else {
                    if (vm.ViewList == null || vm.ViewList == "") {

                        vm.ViewList.push({ "SUB_MODULE_NAME": "", "SUB_MODULE_CODE": "", "VIEW_NAME": "Default View", "VIEW_ID": 0, "IS_APPLICABLE_TO_ALL": 1, "MODULE_NAME": "", "CREATED_AT": "", "IS_SLECTED_USER_ID": 1, "CAN_EDIT": 0, "ROWNUMBER": 0, "VIEW_TYPE": "", "USER_LIST": "" });
                    }
                    else {
                        vm.ViewList.splice(indx, 0, { "SUB_MODULE_NAME": "", "SUB_MODULE_CODE": "", "VIEW_NAME": "Default View", "VIEW_ID": 0, "IS_APPLICABLE_TO_ALL": 1, "MODULE_NAME": "", "CREATED_AT": "", "IS_SLECTED_USER_ID": 1, "CAN_EDIT": 0, "ROWNUMBER": 0, "VIEW_TYPE": "", "USER_LIST": "" });

                    }
                }
                setTimeout(() => {
                    if (vm.ViewListId > 0) {
                        vm.$refs.tgList.$refs.tgListHeaderButtons.ViewListId = vm.ViewListId;
                    } else {
                        vm.$refs.tgList.$refs.tgListHeaderButtons.ViewListId = "0";
                    }
                }, 1000);

            });
        },
        DefaultView: function () {

            var vm = this;
            var obj = {
                ModuleName: 'CRM',
                SubmoduleCode: 'CRM_LEADS'
            };
            var objectPostString = JSON.stringify(obj);
            LeadDataService.ClearView(objectPostString).then(function (response) {
                if (response.data != null) {
                    if (response.data.code == "1" || response.data.Code == "1") {
                        vm.ShowAlert(vm.$t("ClearSuccess", [vm.$t("DefaultView")]), 'success', true, vm.$t('Alert'));
                        //vm.$emit('RefreshManageView');
                        vm.FetchData();
                    }
                    else {
                        vm.ShowAlert(vm.$t("ErrorWhileProcessingRequest"), 'failure', true, vm.$t('Alert'));
                    }
                }
                else {
                    vm.ShowAlert(vm.$t("ErrorWhileProcessingRequest"), 'failure', true, vm.$t('Alert'));
                }
            });
        },
        OnApplyView(viewId) {

            var vm = this;
            if (viewId == '0') {
                vm.DefaultView()
            }
            else {
                var obj = {
                    ViewId: viewId,
                    ModuleName: 'CRM',
                    SubmoduleCode: 'CRM_LEADS'
                };
                var objectPostString = JSON.stringify(obj);
                LeadDataService.ApplyView(objectPostString).then(function (response) {
                    if (response.data != null) {
                        if (response.data.code == "1" || response.data.Code == "1") {
                            vm.ShowAlert(vm.$t("ApplySuccess", [vm.$t("View")]), 'success', true, vm.$t('Alert'));
                            vm.$emit('RefreshManageView');
                            vm.FetchData();
                        }
                        else {
                            vm.ShowAlert(vm.$t("AddedError", [vm.$t("View")]), 'failure', true, vm.$t('Alert'));
                        }
                    }
                    else {
                        vm.ShowAlert(vm.$t("AddedError", [vm.$t("View")]), 'failure', true, vm.$t('Alert'));
                    }
                });

            }
        },
        renderActions: function (row) {
            var self = this;
            let rtnActionArray = [];
            self.listActions.forEach(actionItem => {
                let action = { ...actionItem };
                switch (action.title) {
                    case 'Quick View':
                    case 'View':
                    case 'Notes':
                        action.isVisible = true;
                        break;
                    case 'Edit':
                        action.isVisible = ((self.isBlank(row.existing_client_id) || self.isBlank(row.project_id)) && (row.status_id != 'Closed' && row.status_id != 'Cancelled'))
                        break;
                    case 'Follow-Ups':
                        action.isVisible = row.status_id != 'Closed';
                        break;
                    case 'Reopen':
                        action.isVisible = row.status_id == 'Closed';
                        break;
                    case 'Convert Lead':
                        action.isVisible = ((self.isBlank(row.existing_client_id) || self.isBlank(row.project_id)) && (row.status_id != 'Closed' && row.status_id != 'Inactive' && row.status_id != 'Draft' && row.status_id != 'Cancelled'))
                        break;
                    default: {
                        action.isVisible = true;
                    }
                }
                rtnActionArray.push(action);
            });
            return rtnActionArray;
        },
        clickEventOfColumn: function (row, column) {
            if (column.COLUMN_NAME == 'name') {
                this.$router.push({ path: '/CRM/ViewLeadDetails/' + row.lead_id + '/CRM/CRM_LEADS' });
            }
        },
        closeConvertLead() {
            this.showConvertLead = false;
            this.FetchData();
        },
        columnDataFormatter: function (row, column) {
            return row[column.COLUMN_NAME];
        },
        commonHeaderButtonClick: function (event) {
            switch (event.callbackfunction) {
                case "downloadExceldata":
                    this.checkPrivilegeForExportToExcel();
                    break;
                case "sendBulkEmail":
                    this.SendBulkEmail();
                    break;
                case "ManageView":
                    this.ManageView();
                    break;
                case "openFilterPopUp":
                    this.openFilterPopUp();
                    break;
                case "checkPrivilegeDetailsForOwner":
                    this.checkPrivilegeDetailsForOwner(event, null);
                    break;
                case "ChangeLeadOwner":
                    this.ChangeLeadOwner();
                    break;
                case "closeLead":
                    this.closeLead();
                    break;
                case "commonDeleteData":
                    this.commonDeleteData();
                    break;
                case "bulkLeadUpdate":
                    this.bulkLeadUpdate();
                    break;
                case "removeFilter":
                    var ths = this;
                    this.searchCondition = '';
                    const removeFilterindex = ths.listheaderbuttons.findIndex(object => {
                        return object.callbackfunction === 'removeFilter';
                    });
                    ths.listheaderbuttons[removeFilterindex].isvisible = false;
                    const openFilterPopUpindex = ths.listheaderbuttons.findIndex(object => {
                        return object.callbackfunction === 'openFilterPopUp';
                    });
                    ths.listheaderbuttons[openFilterPopUpindex].iconClass = 'fa fa-filter';
                    try {
                        ths.appliedFilter = [];
                    } catch (e) { };
                    ths.FetchData();
                    break;
                case "setTourGuideSteps":
                    this.setTourGuideSteps(0);
                    break;
            }
        },
        actionButtonClick: function (callbackfunction, item, index, event) {
            var vm = this;
            switch (callbackfunction) {
                case 'openQuickLeadViewModal':
                    vm.openQuickLeadViewModal(item.lead_id);
                    break;
                case 'checkPrivilegeView':

                    break;
                case 'checkPrivilegeDetails':

                    break;
                case 'openNoteListPopUp':
                    vm.openNoteListPopUp(item, index);
                    break;
                case 'openAddNewEvent':
                    vm.openAddNewEvent(item.lead_id, item);
                    break;
                case 'ReopenLead':
                    vm.confirmR(vm.$t("AreYouSuretoReopenLead"), true, (vm.$t("Close") + "  " + vm.$t("Lead")), function (result) {
                        var postJSON = {
                            ids: item.lead_id,
                        };
                        var objectPostString = JSON.stringify(postJSON);
                        LeadDataService.reopenLead(objectPostString).then(function (response) {
                            if (response.data[0].Status == "Success") {
                                if (response.data[0].Value != 'CONVERTED_TO_CONTRACT' && response.data[0].Value != 'CONVERTED_TO_DEAL') {
                                    vm.FetchData();
                                    vm.ShowAlert(vm.$t('LeadReopenedSuccessfully'), "success", vm.$t("Alert"));
                                } else {
                                    vm.ShowAlert(vm.$t('CantReopenDueToConverted'), "warning", vm.$t("Alert"));
                                }
                            }
                            else {
                                vm.ShowAlert(vm.$t('ReopenLeadError'), "failure", vm.$t("Alert"));
                            }
                        });
                    });
                    break;
                case 'openConvertLeadModel':
                    LeadDataService.CheckPrivilege(vm.privilegeParams + 'ConvertLead')
                        .then(function (response) {
                            if (response.data == true) {

                                if (item != null && item.is_additional_lead_owner != "NO" && item.is_additional_lead_owner != "") {
                                    var json = JSON.parse(item.is_additional_lead_owner);
                                    var prmsn = json.filter(function (c) { return c.permission_code == "UpdateLead" });
                                    if (prmsn.length > 0) {
                                        var convertLeadHeader = ((item.client_first_name != null) ? item.client_first_name : '') + ' ' + ((item.client_last_name != null) ? item.client_last_name : '');
                                        vm.openConvertLeadViewModel(item.lead_id, convertLeadHeader);
                                    }
                                    else {
                                        vm.ShowAlert(vm.$t("additionalOwnerAuthorityWarning"), "warning", true, vm.$t("Alert"));
                                    }
                                } else {
                                    var convertLeadHeader = ((item.client_first_name != null) ? item.client_first_name : '') + ' ' + ((item.client_last_name != null) ? item.client_last_name : '');
                                    vm.openConvertLeadViewModel(item.lead_id, convertLeadHeader);
                                }
                            }
                            else {
                                vm.ShowAlert('You are not authorized', "failure", true, "Alert");
                            }
                        });

                    break;
            }
        },
        pagerMethod: function (value) {
            this.PageSize = value.PageSize;
            this.PageNumber = value.PageNumber;
            this.FetchData();
        },
        leftCommonSearch: function (value) {
            this.PageNumber = value.PageNumber;
            this.isPaged = 1;
            if (typeof value.searchCondition != 'undefined') {
                this.searchCondition = value.searchCondition;
            }
            else {
                this.searchCondition = "";
            }
            this.FetchData();
        },
        openFilterPopUp: function (source_id) {
            this.showFilter = true;
            this.cancelOrRefresh();

        },
        cancelOrRefresh: function () {
            this.clientemail = "";
            this.selectedLeadOwner = "";
            this.NameSearch = "";
            this.CompanyName = "";
            this.hdnOwnerId = "";
            this.conditionForInstantSearch = "";
            this.IsAnySearch = false;
            if (this.showFilter != true) {
                this.FetchData();
            }

        },
        ManageView: function () {
            var vm = this;
            this.ShowManageView = true;
            $("#modalManageView").modal('show');
            setTimeout(function () {
                $("#modalManageView").modal('show');
                setTimeout(function () {
                    vm.SetBootstraptoolTip();
                }, 200);
            }, 1000);
        },
        checkPrivilegeDetailsForOwner: function (e, item) {
            var vm = this;
            vm.openAdditionalOwnerpopup();

        },
        checkPrivilegeForExportToExcel: function () {
            var vm = this;
            LeadDataService.CheckPrivilege(vm.privilegeParams + 'ExportLeads')
                .then(function (response) {
                    if (response.data == true) {
                        vm.FetchData(true);
                    }
                    else {
                        vm.ShowAlert('You are not authorized', "failure", true, "Alert");
                    }
                })
        },
        sortdata: function (s) {
            var SortDir = "sort tb_headerSortDown";
            this.SortBy = s;
            if (s === this.SortBy) {
                if (this.SortExp == "") {
                    this.SortExp = "ASC";
                    SortDir = "sort tb_headerSortDown";
                }
                else if (this.SortExp == "ASC") {
                    this.SortExp = "DESC";
                    SortDir = "sort tb_headerSortUp";
                }
                else {
                    this.SortExp = "ASC";
                    SortDir = "sort tb_headerSortDown";
                }
            }
            this.FetchData();
            $("#" + s + '  span:first-child').attr("class", SortDir);
        },
        getRequestParams: function (pageNum, pageSize, sortBy, sortExp, isPaged, searchcondition) {
            let params = {};
            if (pageNum) { params["pageNum"] = pageNum; }
            if (searchcondition) { params["searchcondition"] = searchcondition; }
            if (isPaged) { params["isPaged"] = isPaged; }
            if (sortBy) { params["sortBy"] = sortBy; }
            if (sortExp) { params["sortExp"] = sortExp; }
            if (pageSize) { params["pageSize"] = pageSize; }
            return params;
        },
        FilterData: function (pageNum, pageSize, sortBy, sortExp, searchcondition, filterItemData) {
            this.pageNum = pageNum;
            this.pageSize = pageSize;
            this.sortBy = sortBy;
            this.sortExp = sortExp;
            this.searchCondition = searchcondition;
            if (typeof filterItemData != null)
                this.appliedFilter.push(filterItemData);
            this.FetchData();
        },
        FetchData: function (downloadExceldata) {
            const params = this.getRequestParams(this.pageNum, this.pageSize, this.sortBy, this.sortExp, this.isPaged, this.searchCondition);
            var vueObj = this;
            vueObj.isLoading = true;
            params.pageSize = vueObj.PageSize;
            params.pageNum = vueObj.PageNumber;
            params.searchcondition = vueObj.searchCondition;
            if (vueObj.PageNumber) { params.pageNum = vueObj.PageNumber; }
            else { vueObj.PageNumber = params.pageNum = 1; }
            if (typeof vueObj.isPaged != 'undefined') { params.isPaged = vueObj.isPaged; }
            else { vueObj.isPaged = params.isPaged = 1; }
            params.isPaged = vueObj.isPaged;
            params.sortBy = vueObj.SortBy;
            params.sortExp = vueObj.SortExp;
            var srchCondition = "";
            if (!this.isBlank(this.searchCondition)) { srchCondition = srchCondition + this.searchCondition; }
            if (!this.isBlank(this.conditionForInstantSearch)) {
                srchCondition = srchCondition + ((!this.isBlank(this.searchCondition)) ? (" AND " + this.conditionForInstantSearch) : this.conditionForInstantSearch);
            }
            if (srchCondition != "") {
                params.searchcondition = srchCondition;
                if (vueObj.appliedFilter.length > 0) {
                    const removeFilterindex = vueObj.listheaderbuttons.findIndex(object => {
                        return object.callbackfunction === 'removeFilter';
                    });
                    vueObj.listheaderbuttons[removeFilterindex].isvisible = true;
                    const openFilterPopUpindex = vueObj.listheaderbuttons.findIndex(object => {
                        return object.callbackfunction === 'openFilterPopUp';
                    });
                    vueObj.listheaderbuttons[openFilterPopUpindex].iconClass = 'fa fa-filter text-success';
                }
            }
            else {
                if (vueObj.appliedFilter.length == 0) {
                    const removeFilterindex = vueObj.listheaderbuttons.findIndex(object => {
                        return object.callbackfunction === 'removeFilter';
                    });
                    vueObj.listheaderbuttons[removeFilterindex].isvisible = false;
                    const openFilterPopUpindex = vueObj.listheaderbuttons.findIndex(object => {
                        return object.callbackfunction === 'openFilterPopUp';
                    });
                    vueObj.listheaderbuttons[openFilterPopUpindex].iconClass = 'fa fa-filter';
                }
            }

            // if (downloadExceldata) {
            //     params.isPaged = 0;
            //     LeadDataService.leadListing(params)
            //         .then(function (response) {
            //             vueObj.isLoading = false;
            //             if (response.data != "" && response.data != null) {
            //                 vueObj.JSONToCSVConvertor(response.data, "Lead-Detail", true);
            //             }
            //             else {
            //                 vueObj.ModelnoRecord = true;
            //             }

            //         });
            // }

            if (downloadExceldata) {
                params.isPaged = 0;
                LeadDataService.leadListing(params)
                    .then(function (response) {
                        vueObj.isLoading = false;

                        // Collect the selected lead IDs from the checked checkboxes
                        var selectedIds = [];
                        $('.chkItems:checkbox:checked').not("[id^='chkAll']").not(".CloseLeadInput").each(function () {
                            selectedIds.push($(this).val());
                        });

                        // Check if there are selected IDs and response data is not empty
                        if (response.data && response.data.data && response.data.data.length > 0 && selectedIds.length > 0) {
                            // Filter the response data's 'data' array to only include selected lead_ids
                            var filteredData = response.data.data.filter(function (lead) {
                                return selectedIds.includes(lead.lead_id.toString());
                            });

                            // If there is filtered data, replace it in response.data and pass it to CSV converter
                            if (filteredData.length > 0) {
                                // Keep the schema and other properties intact, and replace only the 'data' array
                                var dataToExport = {
                                    ...response.data,  // Spread to copy existing properties
                                    data: filteredData  // Replace the data array with the filtered data
                                };

                                // Now pass the properly structured data to the CSV converter
                                vueObj.JSONToCSVConvertor(dataToExport, "Lead-Detail", true);
                            } else {
                                vueObj.ModelnoRecord = true; // Show a message if no matching records found
                            }
                        }
                        //is nothing selected then get all downloaded 
                        else if (response.data != "" && response.data != null) {
                            vueObj.JSONToCSVConvertor(response.data, "Lead-Detail", true);
                        }
                        else {
                            vueObj.ModelnoRecord = true; // Show a message if no data or no IDs selected
                        }
                    })
                    .catch(function (error) {
                        console.error("Error fetching lead listing: ", error);
                        vueObj.isLoading = false;
                    });
            }
            else {
                LeadDataService.leadListing(params)
                    .then(function (response) {
                        if (response.data != "" && response.data != null) {
                            vueObj.Headers = response.data.schema;
                            vueObj.Headers.forEach((column) => {
                                column.DISPLAY_NAME = vueObj.$t(column.DISPLAY_NAME ? column.DISPLAY_NAME : column.COLUMN_NAME);
                                column.settings = null;
                                if (column.COLUMN_NAME == 'name') {
                                    column.settings = {
                                        clickEvent: vueObj.clickEventOfColumn,
                                        formatter: vueObj.columnDataFormatter
                                    }
                                }
                                if (column.COLUMN_NAME == 'status_id') {
                                    column.settings = {
                                        isInSlot: true
                                    }
                                }
                            });
                            if (response.data.data.length > 0) {
                                vueObj.LeadData = response.data.data;
                                vueObj.LeadData.forEach((row) => {
                                    row.isCheckBoxDisabled = false;
                                    row.additionalClass = '';
                                    if (row.status_id == 'Closed') {
                                        row.additionalClass = 'warning-bar';
                                    }
                                    if (row.is_sample_data == true) {
                                        row.additionalClass = "sample-bar";
                                    }
                                    if (row.status_id == 'Closed' || row.is_additional_lead_owner != 'NO') {
                                        row.isCheckBoxDisabled = true;
                                    }
                                    row.rowDetailsUrl = '';
                                    if (row.rowDetailsUrl == '') {
                                        row.rowDetailsUrl = '/CRM/ViewLeadDetails/' + row.lead_id + '/CRM/CRM_LEADS';
                                    }
                                });
                                vueObj.TotalRecords = response.data.data[0].total_records;
                                vueObj.TotalPages = Math.ceil(vueObj.TotalRecords / vueObj.PageSize);
                                vueObj.CurrentPage = vueObj.PageNumber;
                                vueObj.noRecord = false;
                                vueObj.GetDdlRecords_ViewList();
                            } else {
                                vueObj.noRecord = true;
                                vueObj.LeadData = [];
                                vueObj.TotalRecords = 0
                            }
                        }
                        else {
                            vueObj.noRecord = true;
                            vueObj.LeadData = [];
                            vueObj.Headers = [];
                            vueObj.TotalRecords = 0
                        }
                        vueObj.isLoading = false;
                    });
            }
        },
        openNoteListPopUp: function (item, indx) {
            var vm = this;
            if (item != null && item.is_additional_lead_owner != "NO" && item.is_additional_lead_owner != "") {
                var json = JSON.parse(item.is_additional_lead_owner);
                var prmsn = json.filter(function (c) { return c.permission_code == "ViewNotes" });
                if (prmsn.length > 0) {
                    vm.LeadIdForViewNote = item;
                    vm.showNoteModal = true;
                } else {
                    vm.ShowAlert(vm.$t("additionalOwnerAuthorityWarning"), "warning", true, vm.$t("Alert"));
                }
            } else {
                vm.LeadIdForViewNote = item;
                vm.showNoteModal = true;
                vm.CurIndex = indx;
            }
        },
        openConvertLeadViewModel: function (lead_id, name) {
            var vm = this;
            vm.confirmR(vm.$t("AreyousuretoConvertLead"), true, null, function () {
                vm.convertLeadValue.value = lead_id;
                vm.convertLeadValue.name = name;
                vm.showConvertLead = (vm.showConvertLead == true) ? false : true;
            });
        },
        openQuickLeadViewModal: function (value) {
            this.idForViewRecord = value;
            this.showQuickLeadViewModal = true;
        },
        openAddNewEvent: function (source_id, item) {
            var vm = this;
            LeadDataService.CheckPrivilege(vm.privilegeParams + 'CreateFollow')
                .then(function (response) {
                    if (response.data == true) {
                        if (item != null && item.is_additional_lead_owner != "NO") {
                            var json = JSON.parse(item.is_additional_lead_owner);
                            var prmsn = json.filter(function (c) { return c.permission_code == "ViewAcitvities" });
                            if (prmsn.length > 0) {
                                vm.souceID = source_id;
                                vm.selectedItem = item;
                                setTimeout(function () {
                                    vm.showAddEventModal = (vm.showAddEventModal == true) ? false : true;
                                }, 500);
                            } else {
                                vm.ShowAlert(this.$t("additionalOwnerAuthorityWarning"), "warning", true, this.$t("Alert"));
                            }
                        } else {
                            vm.souceID = source_id;
                            vm.selectedItem = item;
                            setTimeout(function () {
                                vm.showAddEventModal = (vm.showAddEventModal == true) ? false : true;
                            }, 300);
                        }
                    }
                    else {
                        vm.ShowAlert('You are not authorized', "failure", true, "Alert");
                    }

                });

        },
        closeQuickViewModal: function () {
            this.idForViewRecord = null;
            this.showQuickLeadViewModal = false;
        },
        closeEventViewModal: function () {
            this.showAddEventModal = false;
        },
        getStatuslistForListing: function (StatusType, lang) {
            var vm = this;
            var url = "langCode=" + lang + "&statusType=" + StatusType + "&hasglobal=true";
            LeadDataService.statusdropdown(url).then(function (response) {
                if (response.data.status == "Success") {
                    var json = response.data.result;
                    vm.StatusListForListing = json.data;
                }
            });
        },
        openAdditionalOwnerpopup: function () {
            this.showAdditionalOwnerPopup = true;
        },
        ChangeLeadOwner: function (event) {
            var varObj = this;
            LeadDataService.CheckPrivilege(varObj.privilegeParams + 'ChangeLeadOwner')
                .then(function (response) {
                    if (response.data == true) {
                        $('.chkItems:checkbox:checked').not("[id^='chkAll']").not(".CloseLeadInput").each(function () {
                            varObj.OwnerIds.push($(this).val());
                            varObj.ModuleType = "Lead";
                        });
                        if (varObj.OwnerIds.length > 0) {
                            varObj.showLeadOwnerModal = (varObj.showLeadOwnerModal == true) ? false : true;
                        }
                        else {
                            alert(varObj.$t("Selectchangeleadowner"));
                        }
                    }
                    else {
                        vm.ShowAlert('You are not authorized', "failure", true, "Alert");
                    }

                });
        },
        SendBulkEmail: function (event) {
            var vm = this;
            LeadDataService.CheckPrivilege(this.privilegeParams + 'SendBulkEmail')
                .then(function (response) {
                    if (response.data == true) {
                        var ids = '';
                        var val = '';
                        $('.chkItems:checkbox:checked').not("[id^='chkAll']").not(".CloseLeadInput").each(function () {
                            if (val.length > 0)
                                val += ',';
                            val += $(this).val();
                            ids = val;
                        });
                        if (ids.length > 0) {
                            vm.modalItem = ids;
                            vm.showAddEmailTemplate = true;
                        }
                    }
                    else {
                        vm.ShowAlert('You are not authorized', "failure", true, "Alert");
                    }
                });
        },
        closeLead: function (event) {
            var vm = this;
            var val = "";
            LeadDataService.CheckPrivilege(vm.privilegeParams + 'CloseLeads')
                .then(function (response) {
                    if (response.data == true) {
                        $('.chkItems:checkbox:checked').not("[id^='chkAll']").not(".CloseLeadInput").each(function () {
                            if (val.length > 0)
                                val += ',';
                            val += $(this).val();
                        });
                        if (val.length > 0) {
                            vm.confirmR(vm.$t("AreyousuretoCloseTheseLeads"), true, (vm.$t("Close") + "  " + vm.$t("Lead")), function () {
                                var postJSON = {
                                    ids: val,
                                };
                                var objectPostString = JSON.stringify(postJSON);
                                LeadDataService.CloseLead(objectPostString).then(function (response) {
                                    if (response.data[0].Status == "Success") {
                                        $("[id^='ChangeOwnerId']").removeClass('enable').addClass('disabled');
                                        $("[id^='AdditionalOwnerId']").removeClass('enable').addClass('disabled');
                                        $("[id^='Sendbulkmail']").removeClass('enable').addClass('disabled');
                                        $("[id^='CloseLeadId']").removeClass('enable').addClass('disabled');
                                        $("[id^='chkAll']").prop("checked", false).removeAttr('checked');
                                        $("[id^='DeleteMultiple']").removeClass('enable').addClass('disabled');
                                        $('.chkItems:checkbox:checked').prop("checked", false).removeAttr('checked');
                                        vm.FetchData();
                                        vm.ShowAlert(vm.$t("LeadClosedSuccessfully", [vm.$t('Lead')]), "success", true, vm.$t("Alert"));
                                    }
                                    else {
                                        vm.ShowAlert(vm.$t("CloseLeadError"), "warning", true, vm.$t("Alert"));
                                    }
                                },);
                            });
                        } else {
                            vm.ShowAlert(vm.$t("PleaseSelectAnyRecordsForFurtherAction"), "warning", true, "Alert");
                        }
                    }
                    else {
                        vm.ShowAlert('You are not authorized', "failure", true, "Alert");
                    }

                });
        },
        bulkLeadUpdate: function () {
            var vm = this;
            var val = "";
            $('.chkItems:checkbox:checked').not("[id^='chkAll']").each(function () {
                if (val.length > 0)
                    val += ',';
                val += $(this).val();
            });
            if (val.length > 0) {
                vm.modalItem = val;
                vm.isShowUpdateBulkLead = true;
            } else {
                vm.ShowAlert(vm.$t("Selectanyrecordtobulkupdate"), "warning", true, "Alert");
            }
        },
        commonDeleteData: function () {
            var vm = this;
            LeadDataService.CheckPrivilege(vm.privilegeParams + 'Delete')
                .then(function (response) {

                    if (response.data == true) {
                        var val = "";
                        $('.chkItems:checkbox:checked').not("[id^='chkAll']").each(function () {
                            if (val.length > 0)
                                val += ',';
                            val += $(this).val();
                        });
                        if (val.length > 0) {
                            vm.confirmR(vm.$t("ConfirmDelete"), true, (vm.$t("Delete") + "  " + vm.$t("Lead")), function () {
                                var postJSON = {
                                    ids: val,
                                    moduleName: "CRM",
                                    subModuleCode: "CRM_LEADS"
                                };
                                var objectPostString = JSON.stringify(postJSON);
                                LeadDataService.deleteActivityData(objectPostString).then(function (response) {
                                    if (response.data[0].Status == "Success") {
                                        $("[id^='chkAll']").prop("checked", false).removeAttr('checked');
                                        $('.chkItems:checkbox:checked').prop("checked", false).removeAttr('checked');
                                        $("[id^='ChangeOwnerId']").removeClass('enable').addClass('disabled');
                                        $("[id^='AdditionalOwnerId']").removeClass('enable').addClass('disabled');
                                        $("[id^='CloseLeadId']").removeClass('enable').addClass('disabled');
                                        $("[id^='DeleteMultiple']").removeClass('enable').addClass('disabled');
                                        vm.ShowAlert(vm.$t('DeletedSuccess', [vm.$t('Lead')]), "Success", true, vm.$t('Alert'));
                                        vm.PageNumber = parseInt(vm.PageNumber) - 1;
                                        if (vm.PageNumber < 0) {
                                            vm.PageNumber = 1;
                                        }
                                        vm.FetchData();
                                    }
                                    else {
                                        vm.ShowAlert(vm.$t('DeletedError', [vm.$t('Lead')]), "failure", true, vm.$t('Alert'));
                                    }
                                    // setTimeout(function () {
                                    //     box.modal('hide');
                                    // }, 2000);
                                },);
                            });
                        } else {
                            vm.ShowAlert(vm.$t("Selectanyrecordtodelete"), "warning", true, "Alert");
                        }
                    }

                });
        },
        onChange: function () {
            var checkCount = $('.chkItems:checked').not("[id^='chkAll']").length;
            if (checkCount > 0) {
                $('#ChangeOwnerId').removeClass('disabled');
                $('#AdditionalOwnerId').removeClass('disabled');
            }
            else {
                $('#ChangeOwnerId').addClass('disabled');
                $('#AdditionalOwnerId').addClass('disabled');
            }

        },
        onCloseLeadOwner() {
            this.showLeadOwnerModal = false;
            this.Headers = [];
            this.LeadData = [];
            $(".action-list-box-ddl").hide("slow");
            this.FetchData();
        }
    }
}
</script>
